/*! Lightweight Modernizr stub for bangundaya.com
 *  Menggantikan Modernizr 2.8.3 yang berat dan memicu forced reflow
 *  Hanya menambahkan class "js" dan beberapa helper dasar.
 */
(function (window, document) {
  "use strict";

  var docEl = document.documentElement;

  // ganti class no-js -> js kalau ada
  if (docEl.className) {
    docEl.className = docEl.className.replace(/\bno-js\b/, "").trim();
  }
  if (!/\bjs\b/.test(docEl.className)) {
    docEl.className += (docEl.className ? " " : "") + "js";
  }

  // Stub Modernizr object
  var Modernizr = {
    _version: "stub-1.0",

    // basic touch detection
    touch:
      "ontouchstart" in window ||
      (window.navigator && window.navigator.maxTouchPoints > 0) ||
      (window.navigator && window.navigator.msMaxTouchPoints > 0),

    // matchMedia helper (dipakai beberapa plugin lama)
    mq: function (query) {
      if (window.matchMedia) {
        return window.matchMedia(query).matches;
      }
      return false;
    },

    // placeholder API supaya tidak error kalau dipanggil
    addTest: function () {
      // sengaja dikosongkan
    },
    testProp: function () {
      return true;
    },
    testAllProps: function () {
      return true;
    },
    prefixed: function (prop) {
      return prop;
    }
  };

  // expose ke global
  window.Modernizr = Modernizr;
})(this, this.document);
